INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '52318c61-a067-4853-affe-682c8aadd76c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro SSE — Streaming from API Routes and Syncing with Island State$escape$,
  $escape$Astro API routes (`src/pages/api/*.ts`) can stream Server-Sent Events by returning a `Response` wrapping a `ReadableStream` with `Content-Type: text/event-stream`. Your adapter (Node, Vercel, Netlify) must support streaming — verify this before shipping.

On the client, native `EventSource` connects to the route. Inside Astro's `<script>` tag, you can dispatch custom events or manipulate the DOM directly. If you're using a React or Svelte island, instantiate `EventSource` inside `useEffect` / `onMount` — it's browser-only and will break SSR hydration if called at module scope.

The cleanest pattern for multi-island state: write incoming SSE payloads to a `nanostores` atom (`@nanostores/react` or `@nanostores/svelte`). Any island subscribing to that atom re-renders automatically without prop-drilling or lifting state into a parent layout.

Critical gotcha: if your project uses hybrid rendering with a static default, your SSE route must explicitly opt out with `export const prerender = false`. Without it, Astro pre-renders the route at build time and returns a hollow static response instead of a live stream.$escape$,
  $escape$// src/pages/api/events.ts
import type { APIRoute } from 'astro';

export const prerender = false;

export const GET: APIRoute = () => {
  const stream = new ReadableStream({
    start(controller) {
      const enc = new TextEncoder();
      const id = setInterval(() => {
        controller.enqueue(enc.encode(`data: ${JSON.stringify({ ts: Date.now() })}\n\n`));
      }, 2000);
      // Cleanup on client disconnect is adapter-dependent
      setTimeout(() => { clearInterval(id); controller.close(); }, 30_000);
    },
  });
  return new Response(stream, {
    headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache' },
  });
};

// src/stores/liveStore.ts  (nanostores)
import { atom } from 'nanostores';
export const $liveData = atom<{ ts: number } | null>(null);

// Inside any island's useEffect / onMount:
// const src = new EventSource('/api/events');
// src.onmessage = (e) => $liveData.set(JSON.parse(e.data));$escape$,
  $escape$typescript$escape$,
