INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8c254f9d-1a59-4eaf-adba-dc28354e88da',
  '00000000-0000-0000-0000-000000000001',
  $escape$Astro Route Params Are Fully Typeable — Here's the Right Way$escape$,
  $escape$Astro's CLI ships three quality gates most teams underuse: `astro check`, `astro build`, and `astro preview`. Run them in sequence to catch issues before they hit a CDN. `astro check` runs the TypeScript compiler across all `.astro` files — including template expressions that `tsc` alone misses. For dynamic routes, Astro infers param types directly from `getStaticPaths` via `InferGetStaticParamsType` and `InferGetStaticPropsType`. Accessing `Astro.params.slug` without this inference types it as `string | undefined`, masking bugs. With proper inference, the type narrows to exactly the keys you defined. Wire `astro check` into CI before `astro build`, then run `astro preview` against the built `dist/` — it spins up the SSR adapter locally, so edge-case 404s and redirect loops surface before the deploy. For monorepos, pass `--root ./apps/web` to scope the check. This three-command pipeline (`check → build → preview`) eliminates an entire class of runtime errors that only appear post-build.$escape$,
  $escape$---
// src/pages/blog/[slug].astro
import type { InferGetStaticParamsType, InferGetStaticPropsType } from 'astro';

export async function getStaticPaths() {
  const posts = await fetch('/api/posts').then(r => r.json());
  return posts.map((p: { slug: string; title: string }) => ({
    params: { slug: p.slug },
    props:  { title: p.title },
  }));
}

type Params = InferGetStaticParamsType<typeof getStaticPaths>; // { slug: string }
type Props  = InferGetStaticPropsType<typeof getStaticPaths>;  // { title: string }

const { slug } = Astro.params as Params;  // narrowed — no undefined
const { title } = Astro.props as Props;
---
<h1>{title}</h1>$escape$,
  $escape$typescript$escape$,
